#include <bits/stdc++.h>
using namespace std;
typedef long long ll;

int n;
ll f[105][105];
int p, a[15];
bool v[15];

ll dfs(int x, int k) {
    if (k == p) return f[x][n];
    ll ans = 1e18;
    for (int i = 0; i < p; i++) {
        int y = a[i];
        if (!v[i]) {
            v[i] = true;
            ans = min(ans, dfs(y, k + 1) + f[x][y]);
            v[i] = false;
        }
    }
    return ans;
}

int main() {
    cin >> n;
    for (int i = 1; i <= n; i++) {
        for (int j = 1; j <= n; j++) {
            cin >> f[i][j];
        }
    }
    cin >> p;
    for (int i = 0; i < p; i++) {
        cin >> a[i];
    }
    for (int k = 1; k <= n; k++) {
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                if (f[i][k] && f[k][j]) {
                    f[i][j] = min(f[i][j], f[i][k] + f[k][j]);
                }
            }
        }
    }
    cout << dfs(1, 0);
    return 0;
}
